# --- Infrastructure as Code (SAM / CloudFormation template generation helper) ---
def generate_sam_template():
    """
    Generates a SAM template for deploying the Lambda + API Gateway with CORS.
    Save the output as template.yaml and deploy with `sam deploy`.
    """
    template = """
AWSTemplateFormatVersion: '2010-09-09'
Transform: AWS::Serverless-2016-10-31
Description: User Data API for SPA with CORS enabled

Globals:
  Function:
    Timeout: 30
    Runtime: python3.12
    MemorySize: 256
  Api:
    Cors:
      AllowMethods: "'GET,POST,PUT,DELETE,OPTIONS'"
      AllowHeaders: "'Content-Type,X-Amz-Date,Authorization,X-Api-Key,X-Amz-Security-Token,X-Requested-With'"
      AllowOrigin: "'*'"
      MaxAge: "'86400'"

Resources:
  UserDataFunction:
    Type: AWS::Serverless::Function
    Properties:
      FunctionName: user-data-api
      Handler: lambda_function.lambda_handler
      CodeUri: .
      Description: Serves user data as JSON for the SPA frontend
      Events:
        HealthCheck:
          Type: Api
          Properties:
            Path: /health
            Method: GET
        GetUsers:
          Type: Api
          Properties:
            Path: /users
            Method: GET
        CreateUser:
          Type: Api
          Properties:
            Path: /users
            Method: POST
        GetUser:
          Type: Api
          Properties:
            Path: /users/{userId}
            Method: GET
        UpdateUser:
          Type: Api
          Properties:
            Path: /users/{userId}
            Method: PUT
        DeleteUser:
          Type: Api
          Properties:
            Path: /users/{userId}
            Method: DELETE
        UsersOptions:
          Type: Api
          Properties:
            Path: /users
            Method: OPTIONS
        UserOptions:
          Type: Api
          Properties:
            Path: /users/{userId}
            Method: OPTIONS

Outputs:
  ApiUrl:
    Description: API Gateway endpoint URL
    Value: !Sub "https://${ServerlessRestApi}.execute-api.${AWS::Region}.amazonaws.com/Prod/"
  FunctionArn:
    Description: Lambda Function ARN
    Value: !GetAtt UserDataFunction.Arn
"""
    return template


